    function _getBridgedSupplyStorage() internal pure returns (BridgedSupply storage $) {
        assembly {
            $.slot := BRIDGED_SUPPLY_STORAGE_LOCATION
        }
    }

    /**
     * @notice Get reference to ERC-7201 blacklist storage
