    "src/RedemptionLogic.sol": {
      "content": "// SPDX-License-Identifier: BUSL-1.1
pragma solidity 0.8.29;

import "@openzeppelin/contracts/utils/math/Math.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

import "./StakedUSDaiStorage.sol";

import "./interfaces/IStakedUSDai.sol";

/**
 * @title Redemption Logic
 * @author MetaStreet Foundation
 */
library RedemptionLogic {
    using EnumerableSet for EnumerableSet.UintSet;

    /*------------------------------------------------------------------------*/
    /* Constants */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Fixed point scale
     */
    uint256 internal constant FIXED_POINT_SCALE = 1e18;

    /**
     * @notice Maximum redemption queue scan count
     */
    uint256 internal constant MAX_REDEMPTION_QUEUE_SCAN_COUNT = 150;

    /**
     * @notice Max active redemptions per controller
     */
    uint256 internal constant MAX_ACTIVE_REDEMPTIONS_COUNT = 50;

    /**
     * @notice Minimum redemption shares
     */
    uint256 internal constant MIN_REDEMPTION_SHARES = 1e18;

    /*------------------------------------------------------------------------*/
    /* Getters */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Get redemption and shares ahead
     * @param redemptionState_ Redemption state
     * @param redemptionId Redemption ID
     * @return Redemption, shares ahead
     */
    function _redemption(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        uint256 redemptionId
    ) external view returns (IStakedUSDai.Redemption memory, uint256) {
        /* Look up redemption */
        IStakedUSDai.Redemption memory redemption_ = redemptionState_.redemptions[redemptionId];

        /* Get shares ahead */
        uint256 sharesAhead;
        uint256 count;
        uint256 prevRedemptionId = redemption_.prev;
        while (prevRedemptionId != 0 && count < MAX_REDEMPTION_QUEUE_SCAN_COUNT) {
            /* Get redemption */
            IStakedUSDai.Redemption memory prevRedemption = redemptionState_.redemptions[prevRedemptionId];

            /* If previous redemption pending is 0, break */
            if (prevRedemption.pendingShares == 0) break;

            /* Add pending shares */
            sharesAhead += prevRedemption.pendingShares;

            /* Get previous redemption */
            prevRedemptionId = prevRedemption.prev;

            /* Increment count */
            count++;
        }

        return (redemption_, sharesAhead);
    }

    /**
     * @notice Get available redemption amount and shares
     * @param redemptionState_ Redemption state
     * @param controller Controller address
     * @return Amount, shares
     */
    function _redemptionAvailable(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        address controller
    ) external view returns (uint256, uint256) {
        uint256 amount;
        uint256 shares;

        /* Get redemption IDs */
        uint256[] memory redemptionIds = redemptionState_.redemptionIds[controller].values();

        /* Iterate through redemption IDs */
        for (uint256 i; i < redemptionIds.length; i++) {
            /* Look up redemption */
            IStakedUSDai.Redemption memory redemption_ = redemptionState_.redemptions[redemptionIds[i]];

            /* If redemption is past cliff, increment amount */
            if (redemption_.cliff < block.timestamp) {
                amount += redemption_.withdrawableAmount;
                shares += redemption_.redeemableShares;
            }
        }

        /* Return amount and shares */
        return (amount, shares);
    }

    /*------------------------------------------------------------------------*/
    /* Helpers */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Withdraw assets
     * @param redemptionState_ Redemption state
     * @param amount Amount to withdraw
     * @param controller Controller address
     * @return Amount withdrawn
     */
    function _withdraw(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        uint256 amount,
        address controller
    ) external returns (uint256) {
        /* Initialize shares, remaining amount and redemption IDs */
        uint256 shares;
        uint256 remainingAmount = amount;
        uint256[] memory redemptionIds = redemptionState_.redemptionIds[controller].values();

        /* Iterate through redemption IDs */
        for (uint256 i; i < redemptionIds.length && remainingAmount > 0; i++) {
            /* Look up redemption */
            IStakedUSDai.Redemption storage redemption_ = redemptionState_.redemptions[redemptionIds[i]];

            /* Skip if not past cliff or redemption amount is 0 */
            if (redemption_.cliff >= block.timestamp || redemption_.withdrawableAmount == 0) continue;

            /* Compute amount to withdraw */
            uint256 amountToWithdraw = Math.min(remainingAmount, redemption_.withdrawableAmount);

            /* Compute shares to redeem */
            uint256 sharesToRedeem = amountToWithdraw == redemption_.withdrawableAmount
                ? redemption_.redeemableShares
                : Math.mulDiv(amountToWithdraw, redemption_.redeemableShares, redemption_.withdrawableAmount);

            /* Update redemption state */
            redemption_.withdrawableAmount -= amountToWithdraw;
            redemption_.redeemableShares -= sharesToRedeem;

            /* Update remaining amount and shares */
            remainingAmount -= amountToWithdraw;
            shares += sharesToRedeem;

            /* If redemption is fully serviced and all shares has been redeemed, */
            /* remove redemption ID */
            if (redemption_.pendingShares == 0 && redemption_.redeemableShares == 0) {
                redemptionState_.redemptionIds[controller].remove(redemptionIds[i]);
            }
        }

        /* Validate withdrawal completed */
        if (remainingAmount != 0) revert IStakedUSDai.InvalidRedemptionState();

        /* Update redemption balance */
        redemptionState_.redemptionBalance -= amount;

        return shares;
    }

    /**
     * @notice Redeem shares
     * @param redemptionState_ Redemption state
     * @param shares Shares to redeem
     * @param controller Controller address
     * @return Amount redeemed
     */
    function _redeem(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        uint256 shares,
        address controller
    ) external returns (uint256) {
        /* Initialize amount, remaining shares and redemption IDs */
        uint256 amount;
        uint256 remainingShares = shares;
        uint256[] memory redemptionIds = redemptionState_.redemptionIds[controller].values();

        /* Iterate through redemption IDs */
        for (uint256 i; i < redemptionIds.length && remainingShares > 0; i++) {
            /* Look up redemption */
            IStakedUSDai.Redemption storage redemption_ = redemptionState_.redemptions[redemptionIds[i]];

            /* Skip if not past cliff or redemption amount is 0 */
            if (redemption_.cliff >= block.timestamp || redemption_.redeemableShares == 0) continue;

            /* Compute shares to redeem */
            uint256 sharesToRedeem = Math.min(remainingShares, redemption_.redeemableShares);

            /* Compute amount to withdraw */
            uint256 amountToWithdraw = sharesToRedeem == redemption_.redeemableShares
                ? redemption_.withdrawableAmount
                : Math.mulDiv(sharesToRedeem, redemption_.withdrawableAmount, redemption_.redeemableShares);

            /* Update redemption state */
            redemption_.withdrawableAmount -= amountToWithdraw;
            redemption_.redeemableShares -= sharesToRedeem;

            /* Update remaining shares and amount */
            remainingShares -= sharesToRedeem;
            amount += amountToWithdraw;

            /* If redemption is fully serviced and all shares has been redeemed, */
            /* remove redemption ID */
            if (redemption_.pendingShares == 0 && redemption_.withdrawableAmount == 0) {
                redemptionState_.redemptionIds[controller].remove(redemptionIds[i]);
            }
        }

        /* Validate redemption completed */
        if (remainingShares != 0) revert IStakedUSDai.InvalidRedemptionState();

        /* Update redemption balance */
        redemptionState_.redemptionBalance -= amount;

        return amount;
    }

    /**
     * @notice Request redeem
     * @param redemptionState_ Redemption state
     * @param timelock_ Timelock
     * @param shares Shares to redeem
     * @param controller Controller address
     * @return Redemption ID
     */
    function _requestRedeem(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        uint64 timelock_,
        uint256 shares,
        address controller
    ) external returns (uint256) {
        /* Validate active redemptions count is less than max allowed */
        if (redemptionState_.redemptionIds[controller].length() == MAX_ACTIVE_REDEMPTIONS_COUNT) {
            revert IStakedUSDai.InvalidRedemptionState();
        }

        /* Validate shares are greater than minimum redemption shares */
        if (shares < MIN_REDEMPTION_SHARES) revert IStakedUSDai.InvalidAmount();

        /* Assign redemption ID */
        uint256 redemptionId = ++redemptionState_.index;

        /* Get current tail */
        uint256 tail = redemptionState_.tail;

        /* Update current tail pointer to next redemption ID */
        redemptionState_.redemptions[tail].next = redemptionId;

        /* Update new tail state */
        redemptionState_.redemptions[redemptionId] = IStakedUSDai.Redemption({
            prev: tail,
            next: 0,
            pendingShares: shares,
            redeemableShares: 0,
            withdrawableAmount: 0,
            controller: controller,
            cliff: uint64(block.timestamp) + timelock_
        });
        redemptionState_.tail = redemptionId;

        /* Update pending shares */
        redemptionState_.pending += shares;

        /* If head is not set, set it to the new redemption ID */
        if (redemptionState_.head == 0) {
            redemptionState_.head = redemptionId;
        }

        /* Add redemption ID */
        redemptionState_.redemptionIds[controller].add(redemptionId);

        return redemptionId;
    }

    /**
     * @notice Process pending redemptions
     * @param redemptionState_ Redemption state
     * @param shares Shares to process
     * @param redemptionSharePrice_ Redemption share price
     * @return Amount processed, true if all redemptions are serviced
     */
    function _processRedemptions(
        StakedUSDaiStorage.RedemptionState storage redemptionState_,
        uint256 shares,
        uint256 redemptionSharePrice_
    ) external returns (uint256, bool) {
        /* Validate shares are available to be serviced */
        if (redemptionState_.pending < shares) {
            revert IStakedUSDai.InvalidRedemptionState();
        }

        /* Get head redemption ID */
        uint256 head = redemptionState_.head;

        /* If head is not set, revert */
        if (head == 0) revert IStakedUSDai.InvalidRedemptionState();

        /* Process redemptions */
        uint256 remainingShares = shares;
        uint256 amountProcessed;
        while (remainingShares > 0 && head != 0) {
            /* Get redemption */
            IStakedUSDai.Redemption storage redemption_ = redemptionState_.redemptions[head];

            /* Compute shares to fulfill */
            uint256 fulfilledShares = Math.min(redemption_.pendingShares, remainingShares);

            /* Compute amount to fulfill */
            uint256 fulfilledAmount = Math.mulDiv(fulfilledShares, redemptionSharePrice_, FIXED_POINT_SCALE);

            /* Update redemption pending, redeemable shares, and withdrawable amount */
            redemption_.pendingShares -= fulfilledShares;
            redemption_.redeemableShares += fulfilledShares;
            redemption_.withdrawableAmount += fulfilledAmount;

            /* Update remaining shares and amount processed */
            remainingShares -= fulfilledShares;
            amountProcessed += fulfilledAmount;

            /* Emit RedemptionProcessed */
            emit IStakedUSDai.RedemptionProcessed(
                head, redemption_.controller, fulfilledShares, fulfilledAmount, redemption_.pendingShares
            );

            /* If redemption is completely fulfilled, update head */
            if (redemption_.pendingShares == 0) head = redemption_.next;
        }

        /* If there are remaining shares, revert */
        if (remainingShares != 0) revert IStakedUSDai.InvalidRedemptionState();

        /* Update redemption state */
        redemptionState_.head = head;
        redemptionState_.pending -= shares;

        /* If head is 0, it means all redemptions are serviced */
        return (amountProcessed, head == 0);
    }
}
"
    },
    "src/positionManagers/BasePositionManager.sol": {
      "content": "// SPDX-License-Identifier: BUSL-1.1
pragma solidity 0.8.29;

import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";

import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";

import "../StakedUSDaiStorage.sol";
import "./PositionManager.sol";

import "../interfaces/external/IWrappedMToken.sol";
import "../interfaces/IBasePositionManager.sol";

/**
 * @title Base Position Manager
 * @author MetaStreet Foundation
 */
abstract contract BasePositionManager is
    AccessControlUpgradeable,
    ReentrancyGuardUpgradeable,
    PositionManager,
    StakedUSDaiStorage,
    IBasePositionManager
{
    /*------------------------------------------------------------------------*/
    /* Constants */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Basis points scale
     */
    uint256 internal constant BASIS_POINTS_SCALE = 10_000;

    /*------------------------------------------------------------------------*/
    /* Immutable state */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Wrapped M token
     */
    IWrappedMToken internal immutable _wrappedMToken;

    /**
     * @notice Admin fee rate
     */
    uint256 internal immutable _adminFeeRate;

    /**
     * @notice Admin fee recipient
     */
    address internal immutable _adminFeeRecipient;

    /*------------------------------------------------------------------------*/
    /* Constructor */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Constructor
     * @param wrappedMToken_ Wrapped M token
     * @param adminFeeRate_ Admin fee rate
     * @param adminFeeRecipient_ Admin fee recipient
     */
    constructor(address wrappedMToken_, uint256 adminFeeRate_, address adminFeeRecipient_) {
        _wrappedMToken = IWrappedMToken(wrappedMToken_);
        _adminFeeRate = adminFeeRate_;
        _adminFeeRecipient = adminFeeRecipient_;
    }

    /*------------------------------------------------------------------------*/
    /* Internal helpers */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc PositionManager
     */
    function _assets(
        ValuationType
    ) internal view virtual override returns (uint256) {
        return _scale(_wrappedMToken.balanceOf(address(this))) + claimableBaseYield();
    }

    /**
     * @notice Scale factor
     * @return Scale factor
     */
    function _scaleFactor() internal view returns (uint256) {
        return 10 ** (18 - IERC20Metadata(address(_wrappedMToken)).decimals());
    }

    /**
     * @notice Helper function to scale up a value
     * @param value Value
     * @return Scaled value
     */
    function _scale(
        uint256 value
    ) internal view returns (uint256) {
        return value * _scaleFactor();
    }

    /**
     * @notice Helper function to scale down a value
     * @param value Value
     * @return Unscaled value
     */
    function _unscale(
        uint256 value
    ) internal view returns (uint256) {
        return value / _scaleFactor();
    }

    /*------------------------------------------------------------------------*/
    /* Getter */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc IBasePositionManager
     */
    function claimableBaseYield() public view returns (uint256) {
        return _scale(_wrappedMToken.accruedYieldOf(address(this)) + _wrappedMToken.accruedYieldOf(address(_usdai)));
    }

    /**
     * @inheritdoc IBasePositionManager
     */
    function adminFeeRate() external view returns (uint256) {
        return _adminFeeRate;
    }

    /**
     * @inheritdoc IBasePositionManager
     */
    function adminFeeRecipient() external view returns (address) {
        return _adminFeeRecipient;
    }

    /*------------------------------------------------------------------------*/
    /* API */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc IBasePositionManager
     */
    function claimBaseYield() external {
        _wrappedMToken.claimFor(address(_usdai));
        _wrappedMToken.claimFor(address(this));
    }

    /*------------------------------------------------------------------------*/
    /* Permissioned API */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc IBasePositionManager
     */
    function depositBaseYield(
        uint256 usdaiAmount
    ) external onlyRole(STRATEGY_ADMIN_ROLE) nonReentrant returns (uint256, uint256) {
        /* Scale down the USDai amount */
        uint256 wrappedMAmount = _unscale(usdaiAmount);

        /* Validate balance */
        if (wrappedMAmount > _wrappedMToken.balanceOf(address(this))) {
            revert InsufficientBalance();
        }

        /* Approve wrapped M token to spend USDai */
        _wrappedMToken.approve(address(_usdai), wrappedMAmount);

        /* Deposit wrapped M token for USDai */
        uint256 usdaiAmount_ = _usdai.deposit(address(_wrappedMToken), wrappedMAmount, 0, address(this));

        /* Calculate admin fee */
        uint256 adminFee_ = (usdaiAmount_ * _adminFeeRate) / BASIS_POINTS_SCALE;

        /* Transfer admin fee to admin fee recipient */
        if (_adminFeeRecipient != address(0) && adminFee_ > 0) {
            _usdai.transfer(_adminFeeRecipient, adminFee_);

            /* Calculate amount less admin fee */
            usdaiAmount_ -= adminFee_;
        }

        /* Emit BaseYieldDeposited */
        emit BaseYieldDeposited(usdaiAmount_, adminFee_);

        return (usdaiAmount_, adminFee_);
    }
}
"
    },
    "src/positionManagers/PoolPositionManager.sol": {
      "content": "// SPDX-License-Identifier: BUSL-1.1
pragma solidity 0.8.29;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/utils/math/Math.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/AccessControlUpgradeable.sol";

import {PositionManager} from "./PositionManager.sol";
import {StakedUSDaiStorage} from "../StakedUSDaiStorage.sol";
import {PoolPositionManagerLogic} from "./PoolPositionManagerLogic.sol";

import {IPoolPositionManager} from "../interfaces/IPoolPositionManager.sol";
import {IPool} from "../interfaces/external/IPool.sol";
import {IPriceOracle} from "../interfaces/IPriceOracle.sol";

/**
 * @title Pool Position Manager
 * @author MetaStreet Foundation
 */
abstract contract PoolPositionManager is
    AccessControlUpgradeable,
    ReentrancyGuardUpgradeable,
    PositionManager,
    StakedUSDaiStorage,
    IPoolPositionManager
{
    using SafeERC20 for IERC20;
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;

    /*------------------------------------------------------------------------*/
    /* Constants */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Pools storage location
     * @dev keccak256(abi.encode(uint256(keccak256("stakedUSDai.pools")) - 1)) & ~bytes32(uint256(0xff));
     */
    bytes32 private constant POOLS_STORAGE_LOCATION = 0x0a32e6e3ec9caf40523489fb56ffc3afa6eadc68c0df235d444c084ba724fc00;

    /*------------------------------------------------------------------------*/
    /* Structures */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Pool position
     * @param ticks Ticks
     * @param redemptionIds Redemption ids
     */
    struct PoolPosition {
        EnumerableSet.UintSet ticks;
        mapping(uint128 => EnumerableSet.UintSet) redemptionIds;
    }

    /**
     * @custom:storage-location erc7201:stakedUSDai.pools
     */
    struct Pools {
        EnumerableSet.AddressSet pools;
        mapping(address => PoolPosition) position;
    }

    /*------------------------------------------------------------------------*/
    /* Immutable state */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Price oracle
     */
    IPriceOracle internal immutable _priceOracle;

    /*------------------------------------------------------------------------*/
    /* Constructor */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Constructor
     * @param priceOracle_ Price oracle
     */
    constructor(
        address priceOracle_
    ) {
        _priceOracle = IPriceOracle(priceOracle_);
    }

    /*------------------------------------------------------------------------*/
    /* Getter */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc IPoolPositionManager
     */
    function pools() external view returns (address[] memory) {
        return _getPoolsStorage().pools.values();
    }

    /**
     * @inheritdoc IPoolPositionManager
     */
    function poolTicks(
        address pool
    ) external view returns (uint256[] memory) {
        return _getPoolsStorage().position[pool].ticks.values();
    }

    /**
     * @inheritdoc IPoolPositionManager
     */
    function priceOracle() external view returns (address) {
        return address(_priceOracle);
    }

    /*------------------------------------------------------------------------*/
    /* Internal helpers */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Get reference to ERC-7201 pools storage
     *
     * @return $ Reference to pools storage
     */
    function _getPoolsStorage() internal pure returns (Pools storage $) {
        assembly {
            $.slot := POOLS_STORAGE_LOCATION
        }
    }

    /**
     * @inheritdoc PositionManager
     */
    function _assets(
        PositionManager.ValuationType valuationType
    ) internal view virtual override returns (uint256 nav_) {
        return PoolPositionManagerLogic._assets(_getPoolsStorage(), _priceOracle, valuationType);
    }

    /*------------------------------------------------------------------------*/
    /* Permissioned API */
    /*------------------------------------------------------------------------*/

    /**
     * @inheritdoc IPoolPositionManager
     */
    function poolDeposit(
        address pool,
        uint128 tick,
        uint256 usdaiAmount,
        uint256 poolCurrencyAmountMinimum,
        uint256 minShares,
        bytes calldata data
    ) external onlyRole(STRATEGY_ADMIN_ROLE) nonReentrant returns (uint256) {
        /* Get pool currency token */
        address poolCurrency = IPool(pool).currencyToken();

        /* Validate pool currency token is supported in price oracle */
        if (!_priceOracle.supportedToken(poolCurrency)) {
            revert UnsupportedCurrency(poolCurrency);
        }

        /* Get USDai balance */
        uint256 usdaiBalance = _usdai.balanceOf(address(this)) - _getRedemptionStateStorage().redemptionBalance;

        /* Validate USDai balance */
        if (usdaiAmount > usdaiBalance) revert InsufficientBalance();

        /* Swap USDai to pool currency token */
        uint256 poolCurrencyAmount =
            _usdai.withdraw(poolCurrency, usdaiAmount, poolCurrencyAmountMinimum, address(this), data);

        /* Add pool and tick */
        Pools storage position = _getPoolsStorage();
        position.pools.add(pool);
        position.position[pool].ticks.add(tick);

        /* Approve pool currency token */
        IERC20(poolCurrency).forceApprove(address(pool), poolCurrencyAmount);

        /* Deposit */
        uint256 shares = IPool(pool).deposit(tick, poolCurrencyAmount, minShares);

        /* Emit PoolDeposited */
        emit PoolDeposited(pool, tick, usdaiAmount, poolCurrencyAmount);

        return shares;
    }

    /**
     * @inheritdoc IPoolPositionManager
     */
    function poolRedeem(
        address pool,
        uint128 tick,
        uint256 shares
    ) external onlyRole(STRATEGY_ADMIN_ROLE) nonReentrant returns (uint128) {
        /* Redeem */
        uint128 redemptionId = IPool(pool).redeem(tick, shares);

        /* Add redemption ID */
        _getPoolsStorage().position[pool].redemptionIds[tick].add(redemptionId);

        /* Emit PoolRedeemed */
        emit PoolRedeemed(pool, tick, shares, redemptionId);

        return redemptionId;
    }

    /**
     * @inheritdoc IPoolPositionManager
     */
    function poolWithdraw(
        address pool,
        uint128 tick,
        uint128 redemptionId,
        uint256 poolCurrencyAmountMaximum,
        uint256 usdaiAmountMinimum,
        bytes calldata data
    ) external onlyRole(STRATEGY_ADMIN_ROLE) nonReentrant returns (uint256) {
        /* Withdraw */
        (uint256 withdrawnShares, uint256 poolCurrencyAmount) = IPool(pool).withdraw(tick, redemptionId);

        /* Validate pool currency amount */
        if (poolCurrencyAmount > poolCurrencyAmountMaximum) revert InvalidPoolCurrencyAmount();

        /* Garbage collect tick info and pool */
        PoolPositionManagerLogic._garbageCollect(_getPoolsStorage(), pool, tick, redemptionId);

        /* Check if withdraw produced currency */
        if (poolCurrencyAmount == 0) return 0;

        /* Get currency token */
        address poolCurrency = IPool(pool).currencyToken();

        /* Approve currency token */
        IERC20(poolCurrency).forceApprove(address(_usdai), poolCurrencyAmount);

        /* Swap currency token to USDai */
        uint256 usdaiAmount = _usdai.deposit(poolCurrency, poolCurrencyAmount, usdaiAmountMinimum, address(this), data);

        /* Emit PoolWithdrawn */
        emit PoolWithdrawn(pool, tick, withdrawnShares, redemptionId, poolCurrencyAmount, usdaiAmount);

        return usdaiAmount;
    }
}
"
    },
    "src/interfaces/IUSDai.sol": {
      "content": "// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title USDai Interface
 * @author MetaStreet Foundation
 */
interface IUSDai is IERC20 {
    /*------------------------------------------------------------------------*/
    /* Errors */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Invalid address
     */
    error InvalidAddress();

    /**
     * @notice Invalid amount
     */
    error InvalidAmount();

    /*------------------------------------------------------------------------*/
    /* Events */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Deposited event
     * @param caller Caller
     * @param recipient Recipient
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param mintAmount Mint amount
     */
    event Deposited(
        address indexed caller,
        address indexed recipient,
        address depositToken,
        uint256 depositAmount,
        uint256 mintAmount
    );

    /**
     * @notice Withdrawn event
     * @param caller Caller
     * @param recipient Recipient
     * @param withdrawToken Withdraw token
     * @param baseTokenAmount Base token amount
     * @param withdrawAmount Withdraw amount
     */
    event Withdrawn(
        address indexed caller,
        address indexed recipient,
        address withdrawToken,
        uint256 baseTokenAmount,
        uint256 withdrawAmount
    );

    /*------------------------------------------------------------------------*/
    /* Getters */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Get swap adapter
     * @return Swap adapter
     */
    function swapAdapter() external view returns (address);

    /**
     * @notice Get base token
     * @return Base token
     */
    function baseToken() external view returns (address);

    /*------------------------------------------------------------------------*/
    /* Public API */
    /*------------------------------------------------------------------------*/

    /**
     * @notice Deposit
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param usdaiAmountMinimum Minimum USDai amount
     * @param recipient Recipient
     * @return USDai amount
     */
    function deposit(
        address depositToken,
        uint256 depositAmount,
        uint256 usdaiAmountMinimum,
        address recipient
    ) external returns (uint256);

    /**
     * @notice Deposit
     * @param depositToken Deposit token
     * @param depositAmount Deposit amount
     * @param usdaiAmountMinimum Minimum USDai amount
     * @param recipient Recipient
     * @param data Data (for swap adapter)
     * @return USDai amount
     */
    function deposit(
        address depositToken,
        uint256 depositAmount,
        uint256 usdaiAmountMinimum,
        address recipient,
        bytes calldata data
    ) external returns (uint256);

    /**
     * @notice Withdraw
     * @param withdrawToken Withdraw token
     * @param usdaiAmount USDai amount
     * @param withdrawAmountMinimum Minimum withdraw amount
     * @param recipient Recipient
     * @return Withdraw amount
     */
    function withdraw(
        address withdrawToken,
        uint256 usdaiAmount,
        uint256 withdrawAmountMinimum,
        address recipient
    ) external returns (uint256);

    /**
     * @notice Withdraw
     * @param withdrawToken Withdraw token
     * @param usdaiAmount USD amount
     * @param withdrawAmountMinimum Withdraw amount minimum
     * @param recipient Recipient
     * @param data Data (for swap adapter)
     * @return Withdraw amount
     */
    function withdraw(
        address withdrawToken,
        uint256 usdaiAmount,
        uint256 withdrawAmountMinimum,
        address recipient,
        bytes calldata data
    ) external returns (uint256);
}
